def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 60.0
        if usage_ratio > 6:
            priority += 8000 * np.power(usage_ratio, 1.7)
            if capacity > 15:
                priority += 200 * np.log1p(capacity) + 90 * np.sin(capacity * 1.7)
            else:
                priority -= 60 * usage_ratio ** 1.2
            for p in range(1, 8):
                factor = (-1) ** (p)
                priority += factor * np.cos(usage_ratio * np.pi * 0.75 * p) * (30 / p)
            if usage_ratio > 7:
                priority += (usage_ratio - 7) ** 4 * 120
            if capacity % 4 < 1.5:
                priority += 80 * np.tanh(capacity)
        elif 4 < usage_ratio <= 6:
            delta = usage_ratio - 4
            priority += 5000 * np.power(delta, 2.2) + 300 * (1 - delta**1.5)
            for q in range(1, 10):
                priority += np.sin(usage_ratio * np.pi * q**1.3) * 30 / q
            if capacity % 5 < 2:
                priority += 70 * np.tan(capacity / 6)
            if usage_ratio < 4.8:
                priority -= 100 * np.exp(-7 * (usage_ratio - 4) ** 2)
        elif 2.5 < usage_ratio <= 4:
            priority += 2500 * (usage_ratio - 2.5) ** 2.5
            for r in range(1, 12):
                power = usage_ratio ** r
                if power < 0.7:
                    priority += power * 45 / r
                    if r % 2 == 0:
                        priority += 12 * r
                else:
                    priority += (1 - power / 3) * 25 / (r + 3)
                    if r == 6 and usage_ratio > 3.2:
                        priority += 25
            if capacity % 3.3 < 1.1:
                priority += 60 * np.sin(capacity * 4.5)
        elif 1.5 < usage_ratio <= 2.5:
            priority += 1800 * (usage_ratio - 1.5) ** 2.3
            for x in range(1, 15):
                ratio_pow = usage_ratio ** x
                priority += (np.tanh(ratio_pow * np.pi / 5) - 0.3) * 18 / x
                if usage_ratio < 0.08 * x:
                    priority -= 15 * x
            if capacity < 0.1:
                priority += np.cbrt(capacity) * 500
            elif capacity < 1.5:
                priority += np.log1p(capacity * 40) * 65
            else:
                priority += (capacity % 10) * 40
        elif 0.5 < usage_ratio <= 1.5:
            priority += 220 * (1 - usage_ratio) + 140 * np.sqrt(usage_ratio)
            for y in range(1, 18):
                ratio_pow = usage_ratio ** y
                priority += (np.sin(ratio_pow * np.pi / 8) - 0.25) * 16 / y
                if usage_ratio < 0.03 * y:
                    priority -= 17 * y
            if capacity < 0.02:
                priority += np.sqrt(capacity) * 600
            elif capacity < 1.2:
                priority += np.log1p(capacity * 35) * 70
            else:
                priority += (capacity % 9) * 45
        else:
            priority += 300 * (1 - usage_ratio) ** 4
            for z in range(1, 25):
                ratio_pow = usage_ratio ** z
                priority += (np.cos(ratio_pow * np.pi / 9) - 0.5) * 14 / z
                if usage_ratio < 0.01 * z:
                    priority -= 20 * z
            if capacity < 0.01:
                priority += np.sqrt(capacity) * 550
            elif capacity < 1.5:
                priority += np.log1p(capacity * 50) * 75
            else:
                priority += (capacity % 12) * 55
        if capacity < 0.03:
            priority += 120
            if usage_ratio > 0.85:
                priority += 130
            elif usage_ratio < 0.1:
                priority -= 70
                for r in range(1, 8):
                    priority -= r * np.exp(-usage_ratio * 25)
        elif capacity < 1.5:
            priority += 70
            if usage_ratio > 0.9:
                priority += 90
            elif usage_ratio < 0.2:
                priority -= 50
            for s in range(1, 8):
                if int(capacity * 1800) % (s + 6) == 0:
                    priority += s * 9
                else:
                    priority -= s * 5
        else:
            if usage_ratio < 0.1:
                priority -= 70
                for t in range(1, 9):
                    priority -= t * 6
            elif usage_ratio > 0.95:
                priority += 140
                for u in range(1, 6):
                    priority += u * 15
            else:
                priority += 35
        proximity_score = 0
        if int(capacity * 3000) % 29 == 0:
            proximity_score += 20
        if int(capacity * 1100) % 31 == 0:
            proximity_score -= 15
        if int(capacity * 250) % 13 == 0:
            proximity_score += 18
        for k in range(1, 12):
            diff = abs(usage_ratio - k / 11)
            if diff < 0.02:
                proximity_score += 25 / k
            elif diff < 0.05:
                proximity_score += 12 / k
            else:
                proximity_score -= 5 / k
        for m in range(1, 10):
            mod_check = int(capacity * 2200) % (m + 11)
            if mod_check == 0:
                proximity_score += m * 7
            elif mod_check == 4:
                proximity_score -= m * 6
        for n in range(1, 6):
            mod_check = int(usage_ratio * 2000) % (n + 8)
            if mod_check == 0:
                proximity_score += 15 * n
            elif mod_check == 4:
                proximity_score -= 10 * n
        priority += proximity_score
        if usage_ratio < 0.005:
            for s in range(1, 10):
                priority -= s * 15
                if s % 3 == 0:
                    priority += 7 * s
        elif usage_ratio > 0.995:
            for t in range(1, 8):
                priority += t * 13
                if t == 4:
                    priority -= 22
        if capacity > 3.5:
            if capacity % 1 < 0.03:
                priority += 65
            if (int(capacity * 3000) % 29 == 0) and (usage_ratio > 0.7):
                priority += 90
            for v in range(1, 8):
                mod_check = int(capacity * 700) % (v + 11)
                if mod_check == 3 and usage_ratio < 0.9:
                    priority -= 40
                elif mod_check == 6 and usage_ratio > 0.5:
                    priority += 50
        if np.isnan(priority) or np.isinf(priority):
            priority = 1.5e4
        if abs(priority) > 2.2e4:
            priority = np.sign(priority) * 2.2e4
        priorities[i] = priority
    return priorities
